// ─────────────────────────────────────────────────────────────
// Oxford Bean Publishing — catalog renderer
// Reads BOOKS from data/catalog.js. Do not edit this file to add
// a book or a retailer — edit data/catalog.js instead.
// ─────────────────────────────────────────────────────────────

function obCoverEl(book, imgClass, placeholderClass) {
  const img = document.createElement("img");
  img.src = book.cover;
  img.alt = book.title + " — cover";
  img.className = imgClass;
  img.onerror = function () {
    const ph = document.createElement("div");
    ph.className = placeholderClass;
    ph.innerHTML = "<span>" + book.title + "</span>";
    img.replaceWith(ph);
  };
  return img;
}

// ── index.html — minimal catalogue grid ──────────────────────
function renderCatalogueGrid(container) {
  if (!container) return;
  container.innerHTML = "";
  BOOKS.forEach(function (book) {
    const a = document.createElement("a");
    a.href = "towle.html#book-" + book.slug;
    a.className = "ob-card";

    const coverWrap = document.createElement("div");
    coverWrap.className = "ob-cover";
    coverWrap.appendChild(obCoverEl(book, "ob-cover-img", "ob-cover-placeholder"));
    if (book.status === "coming-soon") {
      const badge = document.createElement("span");
      badge.className = "ob-badge";
      badge.textContent = "Coming Soon";
      coverWrap.appendChild(badge);
    }

    const info = document.createElement("div");
    info.className = "ob-card-info";
    info.innerHTML =
      "<h4>" + book.title + (book.subtitle ? ": " + book.subtitle : "") + "</h4>" +
      '<span class="ob-card-author">' + book.author + "</span>" +
      '<span class="ob-card-genre">' + book.genre + "</span>";

    a.appendChild(coverWrap);
    a.appendChild(info);
    container.appendChild(a);
  });
}

// ── towle.html — full book cards with retailer links ─────────
function renderBookCards(container) {
  if (!container) return;
  container.innerHTML = "";
  BOOKS.forEach(function (book) {
    const card = document.createElement("div");
    card.className = "book-card";
    card.id = "book-" + book.slug;

    const coverWrap = document.createElement("div");
    coverWrap.className = "book-cover-wrap";
    if (book.status === "coming-soon") {
      const badge = document.createElement("span");
      badge.className = "book-badge";
      badge.textContent = "Coming Soon";
      coverWrap.appendChild(badge);
    }
    coverWrap.appendChild(obCoverEl(book, "book-cover", "cover-placeholder"));

    const meta = document.createElement("div");
    meta.className = "book-meta";

    let isbnLine = "Oxford Bean Publishing · " + book.year + " · ISBN " + book.isbn;
    if (book.isbnEbook) isbnLine += " · Ebook ISBN " + book.isbnEbook;

    meta.innerHTML =
      '<p class="book-genre">' + book.genre + (book.series ? " · " + book.series : "") + "</p>" +
      '<h3 class="book-title">' + book.title + (book.subtitle ? ": <em>" + book.subtitle + "</em>" : "") + "</h3>" +
      '<p class="book-publisher">' + isbnLine + "</p>" +
      '<p class="book-desc">' + book.blurb + "</p>";

    if (book.synopsis && book.synopsis.length) {
      const toggle = document.createElement("button");
      toggle.className = "synopsis-toggle";
      toggle.setAttribute("aria-expanded", "false");
      toggle.innerHTML = '<span class="toggle-arrow">\u203a</span>&nbsp; Read Synopsis';

      const body = document.createElement("div");
      body.className = "synopsis-body";
      body.innerHTML = book.synopsis.map(function (p) { return "<p>" + p + "</p>"; }).join("");
      if (book.synopsisQuote) {
        body.innerHTML += '<p class="bot-quote">' + book.synopsisQuote + "</p>";
      }

      toggle.addEventListener("click", function () {
        const isOpen = body.classList.toggle("open");
        toggle.classList.toggle("open", isOpen);
        toggle.setAttribute("aria-expanded", String(isOpen));
        toggle.innerHTML = '<span class="toggle-arrow">' + (isOpen ? "\u2039" : "\u203a") +
          "</span>&nbsp; " + (isOpen ? "Hide Synopsis" : "Read Synopsis");
      });

      meta.appendChild(toggle);
      meta.appendChild(body);
    }

    const actions = document.createElement("div");
    actions.className = "book-actions";
    book.retailers.forEach(function (r, i) {
      const a = document.createElement("a");
      a.href = r.url;
      a.className = i === 0 ? "btn-dark" : "btn-ghost";
      a.textContent = r.format ? r.name + " — " + r.format : r.name;
      actions.appendChild(a);
    });
    const eventBtn = document.createElement("a");
    eventBtn.href = "#contact";
    eventBtn.className = "btn-ghost";
    eventBtn.textContent = "Book an Event";
    actions.appendChild(eventBtn);

    if (book.bookClub && book.bookClub.length) {
      const clubBtn = document.createElement("a");
      clubBtn.href = "bookclub.html#" + book.slug;
      clubBtn.className = "btn-ghost";
      clubBtn.textContent = "Book Club Guide";
      actions.appendChild(clubBtn);
    }

    if (book.excerpt && book.excerpt.length) {
      const sampleBtn = document.createElement("a");
      sampleBtn.href = "sample.html#" + book.slug;
      sampleBtn.className = "btn-ghost";
      sampleBtn.textContent = "Read a Sample";
      actions.appendChild(sampleBtn);
    }

    meta.appendChild(actions);

    card.appendChild(coverWrap);
    card.appendChild(meta);
    container.appendChild(card);
  });
}

// ── bookclub.html — standalone printable/downloadable guide ──
function renderBookClubGuide(container) {
  if (!container) return;
  const slug = (location.hash || "").replace("#", "");
  const book = BOOKS.find(function (b) { return b.slug === slug; });

  if (!book) {
    container.innerHTML =
      '<p class="guide-missing">Choose a book below to view its discussion guide.</p>' +
      renderGuidePicker();
    return;
  }
  if (!book.bookClub || !book.bookClub.length) {
    container.innerHTML =
      "<h1>" + book.title + "</h1>" +
      '<p class="guide-missing">A book club guide for this title isn\u2019t ready yet — check back soon.</p>' +
      '<p><a href="towle.html#book-' + book.slug + '">&larr; Back to the book</a></p>';
    return;
  }

  const questions = book.bookClub.map(function (q) { return "<li>" + q + "</li>"; }).join("");
  container.innerHTML =
    '<p class="guide-eyebrow">Oxford Bean Publishing — Reading Group Guide</p>' +
    "<h1>" + book.title + (book.subtitle ? ": " + book.subtitle : "") + "</h1>" +
    '<p class="guide-author">by ' + book.author + "</p>" +
    '<p class="guide-print-hint">Use your browser\u2019s Print (Ctrl/Cmd+P) and choose \u201cSave as PDF\u201d to download this guide.</p>' +
    '<button class="btn-dark guide-print-btn" onclick="window.print()">Print / Save as PDF</button>' +
    (book.bookClubIntro ? '<p class="guide-intro">' + book.bookClubIntro + "</p>" : "") +
    "<ol>" + questions + "</ol>" +
    (book.bookClubOutro ? '<p class="guide-outro">' + book.bookClubOutro + "</p>" : "") +
    '<p><a href="towle.html#book-' + book.slug + '">&larr; Back to the book</a></p>';
}

function renderGuidePicker() {
  const withGuides = BOOKS.filter(function (b) { return b.bookClub && b.bookClub.length; });
  if (!withGuides.length) return "<p>No book club guides are available yet.</p>";
  return "<ul>" + withGuides.map(function (b) {
    return '<li><a href="bookclub.html#' + b.slug + '">' + b.title + "</a></li>";
  }).join("") + "</ul>";
}

// ── sample.html — standalone writing-sample page ──────────────
function renderSample(container) {
  if (!container) return;
  const slug = (location.hash || "").replace("#", "");
  const book = BOOKS.find(function (b) { return b.slug === slug; });

  if (!book) {
    container.innerHTML =
      '<p class="guide-missing">Choose a book below to read a sample.</p>' +
      renderSamplePicker();
    return;
  }
  if (!book.excerpt || !book.excerpt.length) {
    container.innerHTML =
      "<h1>" + book.title + "</h1>" +
      '<p class="guide-missing">A sample for this title isn\u2019t posted yet — check back soon.</p>' +
      '<p><a href="towle.html#book-' + book.slug + '">&larr; Back to the book</a></p>';
    return;
  }

  const paragraphs = book.excerpt.map(function (p) { return "<p>" + p + "</p>"; }).join("");
  container.innerHTML =
    '<p class="guide-eyebrow">Oxford Bean Publishing — A Sample</p>' +
    "<h1>" + book.title + (book.subtitle ? ": " + book.subtitle : "") + "</h1>" +
    '<p class="guide-author">by ' + book.author + "</p>" +
    '<div class="sample-text">' + paragraphs + "</div>" +
    '<p><a href="towle.html#book-' + book.slug + '">&larr; Back to the book</a></p>';
}

function renderSamplePicker() {
  const withSamples = BOOKS.filter(function (b) { return b.excerpt && b.excerpt.length; });
  if (!withSamples.length) return "<p>No samples are available yet.</p>";
  return "<ul>" + withSamples.map(function (b) {
    return '<li><a href="sample.html#' + b.slug + '">' + b.title + "</a></li>";
  }).join("") + "</ul>";
}

// ── towle.html — ISBN line in the "Where to Find It" callout ─
function renderIsbnSummary(container) {
  if (!container) return;
  container.textContent = "Ingram ISBNs — " +
    BOOKS.map(function (b) { return b.title + ": " + b.isbn; }).join(" · ");
}
